event eProxyReadReq: (key: int, requester: machine, podId: int, reqId: int);
event eProxyWriteReq: (key: int, value: int, requester: machine, podId: int, reqId: int);
event eProxyTick;

type tProxyReq = (isWrite: bool, key: int, value: int, requester: machine, podId: int, reqId: int);

machine StorageProxy {
    var db: machine;
    var queue: seq[tProxyReq];
    var inflight: map[int, tProxyReq];
    var committed: map[int, int];

    start state Init {
        entry (p: (db: machine)) {
            db = p.db;
            queue = default(seq[tProxyReq]);
            inflight = default(map[int, tProxyReq]);
            committed = default(map[int, int]);
            goto Ready;
        }
    }

    state Ready {
        on eProxyReadReq do (r: (key: int, requester: machine, podId: int, reqId: int)) {
            var req: tProxyReq;
            var served: bool;
            served = false;
            req = (isWrite = false, key = r.key, value = 0, requester = r.requester, podId = r.podId, reqId = r.reqId);
            served = MaybeServeReadFromCache(req);
            if (!served) {
                Enqueue(req);
            }
        }

        on eProxyWriteReq do (w: (key: int, value: int, requester: machine, podId: int, reqId: int)) {
            var req: tProxyReq;
            req = (isWrite = true, key = w.key, value = w.value, requester = w.requester, podId = w.podId, reqId = w.reqId);
            Enqueue(req);
        }

        on eStorageReadResp do (resp: (key: int, value: int)) {
            var req: tProxyReq;
            assert resp.key in inflight, "StorageProxy: read resp for key not in inflight!";
            req = inflight[resp.key];
            assert !req.isWrite, "StorageProxy: read resp matched to write req!";
            committed[resp.key] = resp.value;
            announce eMonitorProxyResponseDelivered, (key = req.key, podId = req.podId, isWrite = false);
            send req.requester, eReadResp, (key = resp.key, value = resp.value, fromCache = false);
            inflight -= (resp.key);
            MaybeForward();
        }

        on eStorageWriteResp do (resp: (key: int, success: bool, value: int)) {
            var req: tProxyReq;
            assert resp.key in inflight, "StorageProxy: write resp for key not in inflight!";
            req = inflight[resp.key];
            assert req.isWrite, "StorageProxy: write resp matched to read req!";
            if (resp.success) {
                committed[resp.key] = resp.value;
            }
            announce eMonitorProxyResponseDelivered, (key = req.key, podId = req.podId, isWrite = true);
            send req.requester, eWriteResp, (key = resp.key, success = resp.success);
            inflight -= (resp.key);
            MaybeForward();
        }

        on eProxyTick do {
            MaybeForward();
        }
    }

    fun Enqueue(req: tProxyReq) {
        var p: int;
        p = sizeof(queue);
        queue += (p, req);
        announce eMonitorProxyEnqueue, (key = req.key, podId = req.podId, isWrite = req.isWrite, pending = sizeof(queue));
        MaybeForward();
    }

    fun MaybeServeReadFromCache(req: tProxyReq) : bool {
        var hasWritePending: bool;
        var canServe: bool;
        hasWritePending = HasPendingWrite(req.key);
        canServe = (req.key in committed) && !hasWritePending;
        if (canServe) {
            announce eMonitorProxyResponseDelivered, (key = req.key, podId = req.podId, isWrite = false);
            send req.requester, eReadResp, (key = req.key, value = committed[req.key], fromCache = true);
            return true;
        }
        return false;
    }

    fun HasPendingWrite(key: int) : bool {
        var i: int;
        var r: tProxyReq;
        if (key in inflight && inflight[key].isWrite) {
            return true;
        }
        i = 0;
        while (i < sizeof(queue)) {
            r = queue[i];
            if (r.key == key && r.isWrite) {
                return true;
            }
            i = i + 1;
        }
        return false;
    }

    fun MaybeForward() {
        var i: int;
        var idx: int;
        var r: tProxyReq;
        var held: bool;
        if (sizeof(queue) == 0) {
            return;
        }
        held = $;
        if (held) {
            announce eMonitorProxyHold, (pending = sizeof(queue));
            send this, eProxyTick;
            return;
        }
        idx = -1;
        i = 0;
        while (i < sizeof(queue)) {
            r = queue[i];
            if (!(r.key in inflight)) {
                idx = i;
                break;
            }
            i = i + 1;
        }
        if (idx == -1) {
            announce eMonitorProxyHold, (pending = sizeof(queue));
            send this, eProxyTick;
            return;
        }
        r = queue[idx];
        queue -= (idx);
        inflight[r.key] = r;
        announce eMonitorProxyForward, (key = r.key, podId = r.podId, isWrite = r.isWrite, pending = sizeof(queue));
        if (r.isWrite) {
            send db, eStorageWrite, (caller = this, key = r.key, value = r.value, podId = r.podId);
        } else {
            send db, eStorageRead, (caller = this, key = r.key, podId = r.podId);
        }
        if (sizeof(queue) > 0) {
            send this, eProxyTick;
        }
    }
}

machine CacheNode {
    var proxy: machine;
    var podId: int;
    var nextReqId: int;
    var pendingReadClients: map[int, seq[machine]];
    var pendingWriteClients: map[int, seq[machine]];

    start state Init {
        entry (p: (proxy: machine, podId: int)) {
            proxy = p.proxy;
            podId = p.podId;
            nextReqId = 1;
            pendingReadClients = default(map[int, seq[machine]]);
            pendingWriteClients = default(map[int, seq[machine]]);
            goto Ready;
        }
    }

    state Ready {
        on eClientRead do (req: (client: machine, key: int)) {
            var q: seq[machine];
            var rid: int;
            if (!(req.key in pendingReadClients)) {
                pendingReadClients[req.key] = default(seq[machine]);
            }
            q = pendingReadClients[req.key];
            q += (sizeof(q), req.client);
            pendingReadClients[req.key] = q;
            rid = nextReqId;
            nextReqId = nextReqId + 1;
            announce eMonitorProxyRequestIssued, (key = req.key, podId = podId, isWrite = false);
            send proxy, eProxyReadReq, (key = req.key, requester = this, podId = podId, reqId = rid);
        }

        on eClientWrite do (req: (client: machine, key: int, value: int)) {
            var q: seq[machine];
            var rid: int;
            if (!(req.key in pendingWriteClients)) {
                pendingWriteClients[req.key] = default(seq[machine]);
            }
            q = pendingWriteClients[req.key];
            q += (sizeof(q), req.client);
            pendingWriteClients[req.key] = q;
            rid = nextReqId;
            nextReqId = nextReqId + 1;
            announce eMonitorProxyRequestIssued, (key = req.key, podId = podId, isWrite = true);
            send proxy, eProxyWriteReq, (key = req.key, value = req.value, requester = this, podId = podId, reqId = rid);
        }

        on eReadResp do (resp: (key: int, value: int, fromCache: bool)) {
            var q: seq[machine];
            var c: machine;
            assert resp.key in pendingReadClients, "CacheNode: unexpected read resp with no pending client";
            q = pendingReadClients[resp.key];
            c = q[0];
            send c, eReadResp, resp;
            q -= (0);
            if (sizeof(q) == 0) {
                pendingReadClients -= (resp.key);
            } else {
                pendingReadClients[resp.key] = q;
            }
        }

        on eWriteResp do (resp: (key: int, success: bool)) {
            var q: seq[machine];
            var c: machine;
            assert resp.key in pendingWriteClients, "CacheNode: unexpected write resp with no pending client";
            q = pendingWriteClients[resp.key];
            c = q[0];
            send c, eWriteResp, resp;
            q -= (0);
            if (sizeof(q) == 0) {
                pendingWriteClients -= (resp.key);
            } else {
                pendingWriteClients[resp.key] = q;
            }
        }
    }
}
